docker exec -i "$container" psql -q -v ON_ERROR_STOP=1 -U postgres <<'SQL'
DO $$
DECLARE
  v_attempt jsonb;
  v_attempt_token uuid;
  v_claimed_token text;
  v_result jsonb;
BEGIN
  v_attempt := public.begin_agrorumo_apple_revocation_attempt(
    '88888888-8888-4888-8888-888888888888',
    'cccccccc-cccc-4ccc-8ccc-cccccccccccc',
    repeat('c', 64)
  );
  IF v_attempt ->> 'action' <> 'exchange_code' THEN
    RAISE EXCEPTION 'apple_exchange_was_not_resumed_from_durable_reservation';
  END IF;
  v_attempt_token := (v_attempt ->> 'attempt_token')::uuid;
  PERFORM public.store_agrorumo_apple_revocation_token(
    '88888888-8888-4888-8888-888888888888',
    'cccccccc-cccc-4ccc-8ccc-cccccccccccc',
    v_attempt_token,
    repeat('c', 64),
    'fixture-refresh-token-never-in-application-table'
  );
  v_attempt := public.begin_agrorumo_apple_revocation_attempt(
    '88888888-8888-4888-8888-888888888888',
    'cccccccc-cccc-4ccc-8ccc-cccccccccccc',
    NULL
  );
  IF v_attempt ->> 'action' <> 'revoke_token' THEN
    RAISE EXCEPTION 'vault_token_was_not_scheduled_for_revocation';
  END IF;
  v_attempt_token := (v_attempt ->> 'attempt_token')::uuid;
  v_claimed_token := public.claim_agrorumo_apple_revocation_token(
    '88888888-8888-4888-8888-888888888888',
    'cccccccc-cccc-4ccc-8ccc-cccccccccccc',
    v_attempt_token
  );
  IF v_claimed_token <> 'fixture-refresh-token-never-in-application-table' THEN
    RAISE EXCEPTION 'vault_token_was_not_recoverable_after_process_boundary';
  END IF;
  -- Simulate a process crash after the token claim. Once its bounded lease
  -- expires, a fresh process must recover the same encrypted token.
  UPDATE public.agrorumo_account_deletion_apple_revocations
     SET lease_expires_at = clock_timestamp() - interval '1 second'
   WHERE request_id = (
     SELECT id FROM public.agrorumo_account_deletion_requests
      WHERE receipt_id = 'dddddddd-dddd-4ddd-8ddd-dddddddddddd'
   );
  v_attempt := public.begin_agrorumo_apple_revocation_attempt(
    '88888888-8888-4888-8888-888888888888',
    'cccccccc-cccc-4ccc-8ccc-cccccccccccc',
    NULL
  );
  IF v_attempt ->> 'action' <> 'revoke_token' THEN
    RAISE EXCEPTION 'apple_revocation_restart_did_not_reclaim_expired_lease';
  END IF;
  v_attempt_token := (v_attempt ->> 'attempt_token')::uuid;
  IF public.claim_agrorumo_apple_revocation_token(
       '88888888-8888-4888-8888-888888888888',
       'cccccccc-cccc-4ccc-8ccc-cccccccccccc',
       v_attempt_token
     ) IS NULL
  THEN
    RAISE EXCEPTION 'apple_revocation_restart_lost_encrypted_token';
  END IF;
  PERFORM public.record_agrorumo_apple_revocation_result(
    '88888888-8888-4888-8888-888888888888',
    'cccccccc-cccc-4ccc-8ccc-cccccccccccc',
    v_attempt_token,
    'retry_pending',
    'apple_token_revocation_failed'
  );
  v_attempt := public.begin_agrorumo_apple_revocation_attempt(
    '88888888-8888-4888-8888-888888888888',
    'cccccccc-cccc-4ccc-8ccc-cccccccccccc',
    NULL
  );
  IF v_attempt ->> 'action' <> 'revoke_token' THEN
    RAISE EXCEPTION 'apple_revocation_retry_lost_encrypted_token';
  END IF;
  v_attempt_token := (v_attempt ->> 'attempt_token')::uuid;
  IF public.claim_agrorumo_apple_revocation_token(
       '88888888-8888-4888-8888-888888888888',
       'cccccccc-cccc-4ccc-8ccc-cccccccccccc',
       v_attempt_token
     ) IS NULL
  THEN
    RAISE EXCEPTION 'repeatable_apple_revocation_claim_failed';
  END IF;
  v_result := public.record_agrorumo_apple_revocation_result(
    '88888888-8888-4888-8888-888888888888',
    'cccccccc-cccc-4ccc-8ccc-cccccccccccc',
    v_attempt_token,
    'revoked',
    'apple_authorization_revoked'
  );
  IF v_result ->> 'apple_authorization_status' <> 'revoked'
     OR EXISTS (SELECT 1 FROM vault.secrets)
     OR NOT EXISTS (
       SELECT 1
         FROM public.agrorumo_account_deletion_apple_revocations
        WHERE state = 'revoked'
          AND token_vault_secret_id IS NULL
          AND revoked_at IS NOT NULL
     )
     OR public.get_agrorumo_account_deletion_replay(
          '88888888-8888-4888-8888-888888888888',
          'cccccccc-cccc-4ccc-8ccc-cccccccccccc'
        ) ->> 'apple_authorization_status' <> 'revoked'
  THEN
    RAISE EXCEPTION 'apple_revocation_finalization_was_not_atomic';
  END IF;
  -- Finalization replay must be a no-op, not a second audit transition.
  v_result := public.record_agrorumo_apple_revocation_result(
    '88888888-8888-4888-8888-888888888888',
    'cccccccc-cccc-4ccc-8ccc-cccccccccccc',
    v_attempt_token,
    'revoked',
    'apple_authorization_revoked'
  );
  IF v_result ->> 'apple_authorization_status' <> 'revoked' THEN
    RAISE EXCEPTION 'apple_revocation_finalization_replay_failed';
  END IF;
  IF EXISTS (
    SELECT 1
      FROM information_schema.columns
     WHERE table_schema = 'public'
       AND table_name LIKE 'agrorumo_account_deletion%'
       AND column_name IN (
         'refresh_token', 'authorization_code', 'apple_subject', 'email', 'user_id'
       )
  ) THEN
    RAISE EXCEPTION 'raw_apple_secret_or_pii_column_was_persisted';
  END IF;
END
$$;

